122: func LeaseSpecToLeaderElectionRecord(spec *coordinationv1.LeaseSpec) *LeaderElectionRecord {
123: 	var r LeaderElectionRecord
124: 	if spec.HolderIdentity != nil {
125: 		r.HolderIdentity = *spec.HolderIdentity
126: 	}
127: 	if spec.LeaseDurationSeconds != nil {
128: 		r.LeaseDurationSeconds = int(*spec.LeaseDurationSeconds)
129: 	}
130: 	if spec.LeaseTransitions != nil {
131: 		r.LeaderTransitions = int(*spec.LeaseTransitions)
132: 	}
133: 	if spec.AcquireTime != nil {
134: 		r.AcquireTime = metav1.Time{Time: spec.AcquireTime.Time}
135: 	}
136: 	if spec.RenewTime != nil {
137: 		r.RenewTime = metav1.Time{Time: spec.RenewTime.Time}
138: 	}
139: 	if spec.PreferredHolder != nil {
140: 		r.PreferredHolder = *spec.PreferredHolder
141: 	}
142: 	if spec.Strategy != nil {
143: 		r.Strategy = *spec.Strategy
144: 	}
145: 	return &r
146: 
147: }
148: 
149: func LeaderElectionRecordToLeaseSpec(ler *LeaderElectionRecord) coordinationv1.LeaseSpec {
150: 	leaseDurationSeconds := int32(ler.LeaseDurationSeconds)
151: 	leaseTransitions := int32(ler.LeaderTransitions)
152: 	spec := coordinationv1.LeaseSpec{
153: 		HolderIdentity:       &ler.HolderIdentity,
154: 		LeaseDurationSeconds: &leaseDurationSeconds,
155: 		AcquireTime:          &metav1.MicroTime{Time: ler.AcquireTime.Time},
156: 		RenewTime:            &metav1.MicroTime{Time: ler.RenewTime.Time},
157: 		LeaseTransitions:     &leaseTransitions,
158: 	}
159: 	if ler.PreferredHolder != "" {
160: 		spec.PreferredHolder = &ler.PreferredHolder
161: 	}
162: 	if ler.Strategy != "" {
163: 		spec.Strategy = &ler.Strategy
164: 	}
165: 	return spec
166: }
