29: func pickBestLeaderOldestEmulationVersion(candidates []*v1beta1.LeaseCandidate) *v1beta1.LeaseCandidate {
30: 	var electee *v1beta1.LeaseCandidate
31: 	for _, c := range candidates {
32: 		if !validLeaseCandidateForOldestEmulationVersion(c) {
33: 			continue
34: 		}
35: 		if electee == nil || compare(electee, c) > 0 {
36: 			electee = c
37: 		}
38: 	}
39: 	return electee
40: }
