42: func pickBestStrategy(candidates []*v1beta1.LeaseCandidate) (v1.CoordinatedLeaseStrategy, error) {
43: 	nilStrategy := v1.CoordinatedLeaseStrategy("")
44: 	if len(candidates) == 0 {
45: 		return nilStrategy, fmt.Errorf("no candidates")
46: 	}
47: 	candidateName := candidates[0].Name
48: 	strategy := candidates[0].Spec.Strategy
49: 	highestBV := getBinaryVersionOrZero(candidates[0])
50: 
51: 	for _, c := range candidates[1:] {
52: 		binVersion := getBinaryVersionOrZero(c)
53: 		result := highestBV.Compare(binVersion)
54: 		if result < 0 {
55: 			strategy = c.Spec.Strategy
56: 			highestBV = binVersion
57: 			candidateName = c.Name
58: 		} else if result == 0 && c.Spec.Strategy != strategy {
59: 			return nilStrategy, fmt.Errorf("candidates %q, %q at same binary version but received differing strategies %s, %s", candidateName, c.Name, strategy, c.Spec.Strategy)
60: 		}
61: 	}
62: 	return strategy, nil
63: }
