111: func isLeaseExpired(clock clock.Clock, lease *v1.Lease) bool {
112: 	currentTime := clock.Now()
113: 	return lease.Spec.RenewTime == nil ||
114: 		lease.Spec.LeaseDurationSeconds == nil ||
115: 		lease.Spec.RenewTime.Add(time.Duration(*lease.Spec.LeaseDurationSeconds)*time.Second).Before(currentTime)
116: }
