118: func isLeaseCandidateExpired(clock clock.Clock, lease *v1beta1.LeaseCandidate) bool {
119: 	currentTime := clock.Now()
120: 	return lease.Spec.RenewTime == nil ||
121: 		lease.Spec.RenewTime.Add(leaseCandidateValidDuration).Before(currentTime)
122: }
